# ── HUD overlay ──────────────────────────────────────────────────────────
draw = ImageDraw.Draw(canvas)
f6 = font(6)
f7 = font(7)

# Top bar — semi-transparent dark strip
draw.rectangle((0, 0, W, 13), fill=(0, 0, 0, 160))

# Left: level + XP bar
draw.text((2, 1), f"LV{STATE.level}", fill="#00ffcc", font=f7)
xp_needed = STATE.level * 10
xp_pct    = min(STATE.xp / xp_needed, 1.0)
bar_w     = 28
draw.rectangle((18, 4, 18 + bar_w, 9), fill="#222")
draw.rectangle((18, 4, 18 + int(bar_w * xp_pct), 9), fill="#00ffcc")

# Right: handshakes + APs
draw.text((W - 48, 1), f"HS:{STATE.handshakes}", fill="#ff2dff", font=f7)

# Bottom bar
draw.rectangle((0, H - 13, W, H), fill=(0, 0, 0, 160))

# Mood message (centre bottom)
msg = STATE.msg[:18]
tw  = draw.textlength(msg, font=f6) if hasattr(draw, "textlength") else len(msg) * 4
draw.text(((W - tw) // 2, H - 12), msg, fill="#ffffff", font=f6)

# APs seen (left bottom)
draw.text((2, H - 12), f"AP:{len(STATE.aps_seen)}", fill="#00ff88", font=f6)

# Uptime (right bottom)
up = STATE.uptime_str()
draw.text((W - len(up)*4 - 2, H - 12), up, fill="#888888", font=f6)

# Peer indicator dots (top right — one dot per peer seen)
for i, _ in enumerate(STATE.peers[:5]):
    draw.ellipse((W - 8 - i*6, 1, W - 3 - i*6, 6), fill="#ff2dff")

return canvas.convert("RGB")
