while True:
    try:
        STATE.set_mood("scanning")
        aps = scan_aps()

        if not aps:
            STATE.set_mood("angry", duration=5)
            time.sleep(10)
            continue

        for bssid, ch, essid in aps:
            STATE.aps_seen.add(bssid)

        STATE.set_mood("excited", duration=3)
        time.sleep(2)

        # Target first AP
        bssid, ch, essid = aps[0]
        got = capture_handshake(bssid, ch, essid)

        if got:
            STATE.handshakes += 1
            STATE.add_xp(5)
            STATE.set_mood("got_one", duration=5)
            print(f"[PWN] Handshake: {essid} ({bssid})")
        else:
            STATE.set_mood("hurt", duration=3)

        time.sleep(5)

    except Exception as e:
        print(f"[PWN] WiFi worker error: {e}")
        STATE.set_mood("hurt")
        time.sleep(10)
